}

body {
  background: var(--color-ink);
  color: var(--color-fg);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  overflow: hidden;
  overscroll-behavior: none;
}

/* Frosted glass surface with an inner top highlight for physical edge refraction. */
.glass {
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.055), rgba(255, 255, 255, 0.018));
  backdrop-filter: blur(22px) saturate(140%);
  -webkit-backdrop-filter: blur(22px) saturate(140%);
  border: 1px solid var(--color-line);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.07),
    0 24px 70px rgba(0, 0, 0, 0.5);
}

@media (prefers-reduced-transparency: reduce) {
  .glass {
    background: #17171b;
    backdrop-filter: none;
    -webkit-backdrop-filter: none;
  }
}

/* Thin custom scrollbars */
* {
  scrollbar-width: thin;
  scrollbar-color: rgba(255, 255, 255, 0.14) transparent;
}
*::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}
*::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.12);
  border-radius: 999px;
}
*::-webkit-scrollbar-track {
  background: transparent;
}

/* Processing scan sweep drawn over the image node while a job runs. */
@keyframes scan {
  0% {
    transform: translateY(-115%);
  }
  100% {
    transform: translateY(115%);
  }
}
.scan-sweep {
  background: linear-gradient(180deg, transparent, rgba(230, 178, 119, 0.3), transparent);
  animation: scan 2.1s cubic-bezier(0.4, 0, 0.2, 1) infinite;
}

@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}
.shimmer {
  background: linear-gradient(90deg, rgba(255, 255, 255, 0.04) 25%, rgba(255, 255, 255, 0.1) 37%, rgba(255, 255, 255, 0.04) 63%);
  background-size: 200% 100%;
  animation: shimmer 1.6s ease-in-out infinite;
}

@keyframes breathe {
  0%,
  100% {
    opacity: 0.5;
  }
  50% {
    opacity: 1;
  }
}
.breathe {
  animation: breathe 2.4s ease-in-out infinite;
}

@media (prefers-reduced-motion: reduce) {
  .scan-sweep,
  .shimmer,
  .breathe {
    animation: none;
  }
}

:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 2px;
}

::selection {
  background: rgba(230, 178, 119, 0.28);
}

textarea,
input {
  font-family: inherit;
}

